const app = window.firebase.initializeApp(firebaseConfig);
const database = window.firebase.database();

export default async function readPostDataFromServer(id) {
  try {
    const snapshot = await database.ref().child("Books").child(id).get();

    if (snapshot.exists()) {
      return snapshot.val();
    } else {
      return undefined;
    }
  } catch (error) {
    return error;
  }
}
