import { useRoute } from "@react-navigation/native";
import React from "react";
import { ScrollView, View } from "react-native";
import Post from "~/common/components/minor/Post";
import readPostDataFromServer from "~/utils/api/firebase";

export default function Book() {
  const { params } = useRoute();
  const [data, setData] = React.useState({});

  const getStaticProps = React.useCallback(async (id) => {
    const data = await readPostDataFromServer(id);

    if (!data) {
      return setData({
        title: "Error",
        writer: "404 Not Found",
        story: "",
        poster: "",
      });
    }

    setData(data);
  }, []);

  React.useEffect(() => {
    getStaticProps(params.id);
  }, [params]);

  return (
    <View style={{ flex: 1 }}>
      <ScrollView
        contentContainerStyle={{
          paddingHorizontal: 12,
          paddingTop: 10,
          paddingBottom: 24,
        }}
      >
        <Post.Title title={params?.title} timestamp={data?.timestamp} />
        <Post.Writer writer={data?.writer} className={"mb-3"} />
        <Post.Image url={data?.poster} />
        <Post.Story story={data?.story} />
      </ScrollView>
      <Post.Audio url={data.mp3} />
    </View>
  );
}
